class Solution {
public:
    int maxSatisfied(vector<int>& customers, vector<int>& grumpy, int minutes) {
        int n = customers.size();
        int satisfied = 0;
        int grumpySatisfied = 0;
        int left = 0;
        for (int right = 0; right < n; right++) {
            satisfied += customers[right];
            if (grumpy[right]) {
                grumpySatisfied += customers[right];
            }
            if (right - left + 1 > minutes) {
                if (grumpy[left]) {
                    grumpySatisfied -= customers[left];
                }
                left++;
            }
            grumpySatisfied = max(grumpySatisfied, grumpySatisfied);
        }
        return satisfied - grumpySatisfied;
    }
};
```

